VALUES
  ('public-health-specialist-moex-00412', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '為了因應COVID-19的疫情，公益短片呈現醫師說明應該怎麼做可以避免病毒傳播的內容。 這樣的影片採用了下列何種訴求？', '["工具訴求", "理性訴求", "啟發訴求", "幽默訴求"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00413', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '對於健康與疾病之相關論述，下列選項何者錯誤？', '["生病（illness，一種不舒適的狀態）乃個人的健康受到病痛的損傷、變壞或傷害的結果", "不同的人對於客觀的疾病有不同的主觀感受，也會表現出不同程度的社會功能障礙", "當前健康促進相關政策，其普遍的共識為以「促進健康及預防疾病」代替傳統的診斷與治 療，以購買「健康」代替購買「治療」", "「患病（sickness）」常被用來表示一個人主觀感覺到的不健全狀態，至於「生病（illness）」 常用來說明有病個人的社會功能障礙狀態"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00414', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '對於健康促進與衛生教育的定義、角色與職責之敘述，下列選項何者錯誤？', '["健康促進係透過增能（Empowerment）之手法使民眾有能力自主改善健康", "健康促進之增能方式，取決於民眾資訊、決策能力、資源、網路等因素的獲得", "1986年渥太華憲章對健康促進定義：「使人們能夠增加對於本身健康之控制並促進其健康 之結果」", "2016年WHO全球健康促進大會之宣言提及健康城市與健康社區為主要介入場域，強調運 用健康識能以減少健康不平等"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00415', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '有關健康促進介入方案的策略，下列敘述何者錯誤？', '["規劃健康促進介入方案策略的前提（assumption）：健康狀況是可以改變的，且適當的預防 策略可以解決已知的健康問題", "規劃健康促進介入方案的策略，應考量社區的物理及社會環境，強化社區資源，使民眾能 相互支持，實行其所有生活功能", "為減少因資源分布不均影響健康不平等現況的差距，應將權力由縣市轉移至中央層級，強 調健康決策過程的建構，並強化社區行動", "健康促進介入方案的策略規劃，應將健康意識置於相關執行步驟及內涵裡面"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00416', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '下列有關影響個人健康行為相關因素之敘述，何者錯誤？', '["文化是影響醫療行為的潛在因素，而社會群體關係扮演中介的角色，因此關係越緊密群體 中的個人，其健康行為受到文化影響的程度也越大", "社會網絡會影響人們健康行為的表現，社會網絡緊密者，其成員更容易遵守團體的行為規範", "家庭對其成員健康行為的養成，具有一定程度且長期性的影響力", "探討個人之健康行為改變是否成功，「認知因素」具有絕對的影響力，並不受其他因素（例 如個人屬性或是特質因素）的干擾"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00417', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '某公司欲執行本年度職場健康促進介入方案的成效評價，下列對各項評價指標之敘述，何者 正確？', '["「了解計畫中的資源運用是否理想」是屬於「過程評價」指標", "「參加介入方案的員工是否更能自我壓力管理」是屬於「結果評價」指標", "「了解員工的行為是否受到介入方案影響而改變」是屬於「過程評價」指標", "「了解介入方案是否依照規劃的進度推動」是屬於「影響評價」指標"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00418', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '國民健康署網站有「健康學習資源」，連結中有文宣手冊及影音連結提供各樣的健康及衛教知 識，內容涵蓋各個人生階段（青少年、銀髮族）可能面對的健康議題。以渥太華憲章（1986 年）的行動綱領來看，這是屬於下列那一項？', '["訂定健康的公共政策", "創造有利健康的環境", "強化社區行動", "發展個人技巧"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00419', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', 'Sallis與Owen（2002年）認為應用生態模式設計健康介入方案時，應注意幾個原則，下列何 者錯誤？', '["需考量健康行為受到多層級因素的影響", "需依健康行為特性選擇適用的生態模式", "多層級介入需要跨部門或跨族群合作", "生態模式之各層級內的考量因素／變項間互為獨立"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00420', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '某校老師發現近來性騷擾事件頻傳，於是以校園社區共同防護網為主題，邀請老師、附近里 長及家長參加，透過會議使學校、家長及社區代表了解性騷擾意義及防護通報等規定及交換 意見。該老師運用的是WHO在GlobalSchoolHealthInitiative中的那一個策略？', '["強化學校執行健康計畫的能力", "運用研究改善學校健康促進計畫", "將健康促進計畫提升為國家層級的政策", "建立健康促進學校的網絡和聯盟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00421', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '某健康促進專家在規劃菸害防制計畫時，將影響吸菸行為的因素歸納為對菸害的知識、對戒 菸的態度及對肺癌的自覺罹患性。這樣的歸納可能會有下列何種情況產生？', '["過度推論造成原子謬誤", "僅著重個人層次的因素造成受害者責備", "將肺癌視為慢性病造成疾病轉型", "推動戒菸但無法降低吸菸盛行率"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00422', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '某健康中心欲進行以預防失智症為題之健康促進計畫，為了解社區居民對失智症的認知，因 此進行問卷調查以收集第一手資料。此計畫可能正處於下列那個階段？', '["發展介入", "執行介入策略", "文獻探討", "需求評估"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00423', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '因應人口快速老化的全球化趨勢，世界衛生組織（WHO）在2007年發布「高齡友善城市指 南」，有關高齡友善城市健康促進介入方案的規劃，下列敘述何者錯誤？', '["某縣市政府以發展「全齡藝文」為目標，將過去只能在展演廳觀賞的音樂藝文活動推廣至 社區日常生活，透過藝術下鄉在家門口開演，傳唱當地老一輩故事，便於長者在親友陪伴 下參加，此為高齡友善城市八大面向介入方案規劃之「親老」", "「高齡友善城市」目標乃創造有利於高齡者活動條件的場域，健康促進介入方案應以減少 場域各項障礙，增進高齡者參與為規劃重點", "「高齡友善城市指南」強調「健康」是基本人權，健康促進介入方案規劃推動「以環境安 全為最高設計原則」的高齡友善城市，落實healthinallpolicies，共創全齡共享、世代宜居 的永續城市", "某縣市政府結合企業及大學實現社會責任力量，推動幸福巴士上路，由企業捐贈小車及當 地民眾私家車權，作為「公車」掛上綠牌，填補山區交通缺口，嘉惠行動不便長者出入， 此為高齡友善城市八大面向介入方案規劃之「暢行」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00424', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '行政院發布自112年3月22日起施行菸害防制新法，以維護國人健康。這個方式屬於渥太華 憲章五大行動綱領的何者？', '["創造支持性環境", "強化社區行動", "建立健康的公共政策", "調整健康服務方向"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00425', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '隨著人口高齡化，許多縣市政府及民間機構紛紛推出銀髮就業平台媒合服務或是高齡就業服 務，這樣的趨勢符合衛生福利部推動高齡友善城市的那個面向？', '["安居", "親老", "敬老", "不老"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00426', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '下列對健康促進與社區營造之關鍵－夥伴關係建立的敘述，何者錯誤？', '["組織與組織間的財務支持，是有利於夥伴關係的因素", "社區組織之在地聲音（localvoiceinaction），設定健康議題的代表性，皆有利於夥伴關係之 建立", "批判與挑戰當前健康政策之執行，有利於組織與組織間之夥伴關係建立", "健康促進政策與社區夥伴關係，考慮因素包含當前健康議題、全球化、結盟合作、永續經 營等"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00427', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '有關壓力、因應與調適中，對於復原力（resilience）之敘述，下列何者錯誤？', '["復原力（resilience）一詞源自拉丁字「resilire」，泛指人或物體具有彈性、韌性或抗壓性， 即使受外力擠壓仍能迅速恢復的一種力量或特質", "依相關理論而言，復原力係指個體面對風險時，能「積極恢復」至正向情緒之因應策略， 無法透過認知教育訓練或環境改變來加以強化", "個人在壓力情境下情緒與認知的平衡，透過自我對話，察覺與轉化情緒，尋找釋放出口， 也是復原力的一部分", "Werner（1995）認為建構復原力涉及三個關鍵環節，分別為風險因子、保護因子和脆弱因子"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00428', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '有關情緒與健康之敘述，下列何者錯誤？', '["透過社會關係與人際互動，適度提供同理心表達、愛、信任與關心，對當事人而言，有助 於其面對壓力源或負面事件", "學者Cassel提出，社會支持是重要的健康社會決定因素，能夠有效降低心理壓力與情緒對 健康危害的影響", "當人們經歷人生重大轉變，例如畢業或結婚，可能為壓力源，亦可能引發疾病發生或影響 健康行為頻率", "對當事人提供自我評價有效的資訊，如有用的回饋與肯定，乃是社會支持類型（House,1981） 分類之「資訊性支持」類型"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00429', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '工作壓力對於個體的身心健康有很大的影響，請問根據工作需求控制模式（Jobdemandcontrol model,Karasek,1979），下列那種工作狀況會產生最大的壓力？', '["高控制、高需求", "低控制、低需求", "低控制、高需求", "高控制、低需求"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00430', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '自殺是一項全球性公共衛生問題，有關自殺防治之敘述，下列何者錯誤？', '["人際關係與社會支持系統能提供支持力量以扮演自殺防治的保護因子，但亦可能提高自殺 的風險性", "自殺是單一因子決定的結果；自殺亦為一過程，由意念、行為意圖、採取自殺行為，期間 長短不一", "性別、年齡、職業、突發事件等原因，都可能成為自殺行為的危險因子", "大多數想要採取自殺行為的人，會發出求救信號；若能及時伸出援手，提供適當支持，可 避免遺憾發生"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00431', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '下列何者屬於職場霸凌（workplacebullying）？', '["某主管認為某員工近期工作表現不佳，因而將該員工請來辦公室談話", "某組內多位員工對於特定同事不滿，因而長期使用各種手法，阻止該同事順利工作", "某組內多位員工認為組長該次分工不均，因而找組長理論", "某員工因家中事故扣光帶薪假，因此遭到主管關切"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00432', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'essay', '近年來學界及媒體，以健保給付不足導致臺灣人平均餘命由過去比韓
